#!/usr/bin/perl
use strict;
use warnings;

my $passfile = "/app/john/run/password.lst";
my $archive = "/app/secrets.7z";
my $output_dir = "/tmp/crack_out";

open(my $fh, '<', $passfile) or die "Cannot open $passfile: $!";

my $count = 0;
my $found = 0;
my $password;

# Pre-read first N passwords to try common ones first
my @common_passwords = qw(password 123456 12345678 qwerty abc123 monkey letmein dragon 111111 baseball iloveyou trustno1 1234567 sunshine master hello freedom whatever);

foreach my $pass (@common_passwords) {
    $count++;
    print "Trying common password: $pass\n";
    system("rm -rf $output_dir 2>/dev/null");
    my $output = `7z x $archive -o$output_dir -p"$pass" 2>&1`;
    if ($output =~ /Everything is Ok/) {
        $found = 1;
        $password = $pass;
        last;
    }
}

if (!$found) {
    # Try from dictionary
    while (my $pass = <$fh>) {
        chomp $pass;
        # Skip comments and empty
        next if $pass =~ /^#/ || $pass =~ /^\s*$/;

        $count++;
        if ($count % 1000 == 0) {
            print "Tried $count passwords...\n";
        }

        system("rm -rf $output_dir 2>/dev/null");
        my $output = `7z x $archive -o$output_dir -p"$pass" 2>&1`;
        if ($output =~ /Everything is Ok/) {
            $found = 1;
            $password = $pass;
            last;
        }

        # Early exit if taking too long
        last if $count > 50000;
    }
}

if ($found) {
    print "\nPassword found: $password\n";

    # Read the secret file
    my $secret_file = "$output_dir/secrets/secret_file.txt";
    open(my $sfh, '<', $secret_file) or die "Cannot open $secret_file: $!";
    my $secret = <$sfh>;
    chomp $secret;
    close($sfh);

    print "Secret: $secret\n";

    # Write solution
